import React, { useState } from 'react';
import Modal from '@mui/material/Modal';
import Box from '@mui/material/Box';
import MenuIcon from '@mui/icons-material/Menu';
import CloseIcon from '@mui/icons-material/Close';
import EmojiEventsIcon from '@mui/icons-material/EmojiEvents';
import GroupsIcon from '@mui/icons-material/Groups';
import CodeIcon from '@mui/icons-material/Code';
import SkillManager from '../components/SkillManager';
import DrawerMenu from '../components/DrawerMenu';
import ContestCard from '../components/ContestCard';
import ContestModal from '../components/ContestModal';
import Header from '../components/Header';

<>
  <ContestModal
    open={modalOpen}
    onClose={() => setModalOpen(false)}
    users={users}
    userSkills={userSkills}
    setUserSkills={setUserSkills}
    matched={matched}
    matchTeam={matchTeam}
    feedbacks={feedbacks}
    onFeedback={handleFeedback}
  />
  <ContestCard onClick={() => setModalOpen(true)} />
  <Header onMenuOpen={() => setDrawerOpen(true)} />
</>


const dummyUsers = [
  { id: 1, name: "홍길동", skills: ["React", "JavaScript"] },
  { id: 2, name: "김철수", skills: ["Python", "Django"] },
  { id: 3, name: "이영희", skills: ["Java", "Spring"] },
  { id: 4, name: "박민수", skills: ["C++", "알고리즘"] },
  { id: 5, name: "최지우", skills: ["UI/UX", "Figma"] },
  { id: 6, name: "정우성", skills: ["Node.js", "Express"] },
  { id: 7, name: "한지민", skills: ["DB", "SQL"] },
  { id: 8, name: "서준호", skills: ["React", "TypeScript"] },
  { id: 9, name: "오세훈", skills: ["AI", "TensorFlow"] },
  { id: 10, name: "임수정", skills: ["Flutter", "모바일"] },
];

function Home() {
  const [modalOpen, setModalOpen] = useState(false);
  const [userSkills, setUserSkills] = useState(["React", "JavaScript"]);
  const [users] = useState(dummyUsers);
  const [matched, setMatched] = useState([]);
  const [feedbacks, setFeedbacks] = useState({});
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [openMenus, setOpenMenus] = useState({});

  const matchTeam = () => {
    const shuffled = [...users].sort(() => Math.random() - 0.5);
    setMatched([shuffled.slice(0, 5), shuffled.slice(5, 10)]);
  };

  const handleFeedback = (teamIndex, isPositive) => {
    setFeedbacks(prev => ({ ...prev, [teamIndex]: isPositive }));
  };

  return (
    <div>
      {/* 헤더 */}
      <header>
        <h1 style={{ color: '#FF6B35', padding: '1rem 2rem' }}>TUP!</h1>
        {!drawerOpen && (
          <button onClick={() => setDrawerOpen(true)} style={{ position: 'absolute', right: '1rem', top: '1rem', background: 'none', border: 'none' }}>
            <MenuIcon style={{ fontSize: '2rem', color: '#FF6B35' }} />
          </button>
        )}
      </header>

      {/* 드로어 메뉴 */}
      <DrawerMenu open={drawerOpen} onClose={() => setDrawerOpen(false)} openMenus={openMenus} onToggle={setOpenMenus} />

      {/* 메인 콘텐츠 */}
      <main style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
        <h2>함께할 <span style={{ color: '#FF6B35' }}>팀원</span>이 필요하신가요?</h2>
        <p>TUP은 공모전 참가자들을 위한 지능형 팀 매칭 플랫폼입니다.<br />
        기술 스택과 관심사를 기반으로 최적의 팀원을 찾아보세요!</p>

        <div onClick={() => setModalOpen(true)} style={{ background: '#fff', padding: '1rem', borderRadius: '12px', boxShadow: '0 4px 10px rgba(0,0,0,0.1)', cursor: 'pointer' }}>
          <EmojiEventsIcon style={{ color: '#FF6B35', fontSize: '2rem' }} /> 2025 AWS x Codetree 프로그래밍 경진대회
        </div>
      </main>

      {/* 모달 */}
      <Modal open={modalOpen} onClose={() => setModalOpen(false)}>
        <Box sx={{ width: '80%', margin: '5% auto', backgroundColor: 'white', p: 4, borderRadius: '12px' }}>
          <h2>공모전 정보</h2>
          <SkillManager skills={userSkills} setSkills={setUserSkills} />

          <button onClick={matchTeam} style={{ marginTop: '1rem', padding: '0.5rem 1rem', background: '#FF6B35', color: 'white', border: 'none', borderRadius: '8px' }}>
            TEAM UP!
          </button>

          {matched.map((team, idx) => (
            <div key={idx} style={{ marginTop: '1rem' }}>
              <h4>팀 {idx + 1}</h4>
              {team.map(user => (
                <div key={user.id}>{user.name} - {user.skills.join(', ')}</div>
              ))}
              <div>
                <button onClick={() => handleFeedback(idx, true)}>👍</button>
                <button onClick={() => handleFeedback(idx, false)}>👎</button>
              </div>
            </div>
          ))}
        </Box>
      </Modal>
    </div>
  );
}

export default Home;
